INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 1000001, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 0.0, -416.5, 1, "2025/01/31 12:00:00", 62, 190801, 3.414, 2, 1, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 2, 1000002, "ミッションをクリアして、\n報酬をゲットしましょう！", 0.0, -416.5, 1, "2025/01/31 12:00:00", 62, 190801, 3.099, 2, 1, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 3, 1000003, "受け取ることができる\n報酬があるようです\n確認してみてください", 0.0, -416.5, 1, "2025/01/31 12:00:00", 63, 190801, 2.801, 2, 1, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 4, 1000004, "報酬がもらえますよ！\nチェックしてみてください", 0.0, -416.5, 2, "2025/01/31 12:00:00", 63, 190801, 0.0, 2, 1, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 5, 1000005, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 0.0, -363.0, 2, "2025/01/31 12:00:00", 64, 190801, 2.12, 1, 1, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 6, 1000006, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 0.0, -363.0, 1, "2025/01/31 12:00:00", 64, 190801, 1.68, 2, 1, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 7, 1000007, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 0.0, -363.0, 2, "2025/01/31 12:00:00", 64, 190801, 2.33, 1, 1, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 101, 1020101, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", -6.0, -285.0, 3, "2025/01/31 12:00:00", 61, 133701, 5.18, 7, 10201, "ラビリスタ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 201, 1020102, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", -2.0, -285.0, 1, "2025/01/31 12:00:00", 61, 133901, 8.77, 2, 10201, "クリスティーナ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 301, 1020103, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", 0.0, -285.0, 6, "2025/01/31 12:00:00", 61, 133801, 15.5, 1, 10201, "ネネカ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 101, 1020201, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", 0.0, -285.0, 2, "2025/02/28 12:00:00", 61, 134301, 9.061, 5, 10202, "ランファ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 201, 1020202, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", 0.0, -285.0, 1, "2025/02/28 12:00:00", 61, 134401, 7.699, 2, 10202, "チカ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 101, 1020301, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", 0.0, -285.0, 1, "2025/03/31 12:00:00", 61, 134601, 8.595, 2, 10203, "アオイ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 201, 1020302, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", 0.0, -285.0, 1, "2025/03/31 12:00:00", 61, 134501, 7.758, 2, 10203, "クローチェ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 101, 1020401, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", 0.0, -285.0, 2, "2025/04/30 12:00:00", 61, 132302, 7.0, 6, 10204, "ルイズマリー");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 201, 1020402, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", 0.0, -285.0, 1, "2025/04/30 12:00:00", 61, 132402, 7.904, 2, 10204, "イロハ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 301, 1020403, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", 0.0, -285.0, 4, "2025/04/30 12:00:00", 61, 132502, 8.487, 2, 10204, "ソノ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 101, 1020502, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", 0.0, -285.0, 1, "2025/05/31 12:00:00", 61, 134901, 8.763, 2, 10205, "カノン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 201, 1020503, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", 0.0, -285.0, 1, "2025/05/31 12:00:00", 61, 134801, 6.417, 3, 10205, "ツムギ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 101, 1020601, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", 0.0, -285.0, 3, "2025/06/30 12:00:00", 61, 135001, 10.335, 7, 10206, "エリス");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 201, 1020602, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", 0.0, -285.0, 2, "2025/06/30 12:00:00", 61, 135101, 6.281, 4, 10206, "シェフィ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 301, 1020603, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", 0.0, -285.0, 1, "2025/06/30 12:00:00", 61, 135201, 12.244, 2, 10206, "プレシア");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 101, 1020701, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", 0.0, -285.0, 2, "2025/07/31 12:00:00", 61, 135301, 6.339, 8, 10207, "クリア");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 201, 1020702, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", 0.0, -285.0, 7, "2025/07/31 12:00:00", 61, 135401, 8.184, 9, 10207, "アネモネ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 101, 1020801, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", 0.0, -285.0, 9, "2025/08/31 12:00:00", 61, 129101, 3.906, 2, 10208, "アイラ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 201, 1020802, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", 0.0, -285.0, 1, "2025/08/31 12:00:00", 61, 129201, 14.465, 2, 10208, "シナツ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 301, 1020803, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", 0.0, -285.0, 4, "2025/08/31 12:00:00", 61, 100101, 8.662, 3, 10208, "ヒヨリ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 401, 1020804, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", 0.0, -285.0, 1, "2025/08/31 12:00:00", 61, 100301, 10.915, 3, 10208, "レイ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 101, 1020901, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", 0.0, -285.0, 1, "2025/09/30 12:00:00", 61, 135802, 6.042, 7, 10209, "ユキノ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 201, 1020902, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", 0.0, -285.0, 4, "2025/09/30 12:00:00", 61, 135903, 9.402, 1, 10209, "サツキ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 301, 1020903, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", 0.0, -285.0, 8, "2025/09/30 12:00:00", 61, 136902, 8.16, 1, 10209, "ルルィ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 101, 1021001, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", 0.0, -285.0, 3, "2025/10/31 12:00:00", 61, 137401, 5.0, 2, 10210, "カスミ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 201, 1021002, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", 0.0, -285.0, 4, "2025/10/31 12:00:00", 61, 136001, 8.12, 1, 10210, "アラクネ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 301, 1021003, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", 0.0, -285.0, 4, "2025/10/31 12:00:00", 61, 136202, 6.386, 2, 10210, "ナーナ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 101, 1021101, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", 0.0, -285.0, 3, "2025/11/30 12:00:00", 61, 136402, 7.438, 4, 10211, "ユイ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 201, 1021102, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", 0.0, -285.0, 1, "2025/11/30 12:00:00", 61, 136302, 8.35, 5, 10211, "ミソラ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 101, 1021201, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", 0.0, -285.0, 1, "2025/12/31 12:00:00", 61, 136501, 5.0, 2, 10212, "シズル");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 201, 1021202, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", 0.0, -285.0, 1, "2025/12/31 12:00:00", 61, 137902, 5.25, 2, 10212, "リノ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 301, 1021203, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", 0.0, -285.0, 1, "2025/12/31 12:00:00", 61, 106801, 7.5, 2, 10212, "ラビリスタ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 101, 1021301, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", 0.0, -285.0, 1, "2026/01/31 12:00:00", 61, 126501, 8.204, 2, 10213, "ライラエル");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 201, 1021302, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", 0.0, -285.0, 1, "2026/01/31 12:00:00", 61, 129701, 7.176, 2, 10213, "ネフィ＝ネラ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 301, 1021303, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", 0.0, -285.0, 1, "2026/01/31 12:00:00", 61, 133101, 8.602, 5, 10213, "ヴァイオレット");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 102, 1021304, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", 0.0, -285.0, 1, "2026/02/06 12:00:00", 61, 138101, 10.14, 3, 10213, "ライラエル");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 202, 1021305, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", 0.0, -285.0, 1, "2026/02/06 12:00:00", 61, 138201, 10.152, 7, 10213, "ネフィ＝ネラ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 302, 1021306, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", 0.0, -285.0, 4, "2026/02/06 12:00:00", 61, 138001, 9.688, 3, 10213, "ヴァイオレット");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 401, 1021307, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", 0.0, -285.0, 2, "2026/02/12 12:00:00", 61, 138301, 5.928, 1, 10213, "ペコリーヌ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 101, 1021401, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", 0.0, -285.0, 4, "2026/02/28 12:00:00", 61, 138702, 9.19, 2, 10214, "ワカナ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 201, 1021402, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", 0.0, -285.0, 1, "2026/02/28 12:00:00", 61, 138802, 8.724, 3, 10214, "シオリ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 101, 1021501, "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", 0.0, -285.0, 4, "2026/03/31 12:00:00", 61, 138902, 7.758, 1, 10215, "グレイス");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 201, 1021502, "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", 0.0, -285.0, 6, "2026/03/31 12:00:00", 61, 139002, 6.375, 4, 10215, "キョウカ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 301, 1021503, "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", 0.0, -285.0, 6, "2026/03/31 12:00:00", 61, 136902, 6.173, 1, 10215, "ルルィ");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 2000001, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 0.0, -416.5, 1, "2026/04/10 12:00:00", 62, 190801, 3.414, 2, 2, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 2, 2000002, "ミッションをクリアして、\n報酬をゲットしましょう！", 0.0, -416.5, 1, "2026/04/10 12:00:00", 62, 190801, 3.099, 2, 2, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 3, 2000003, "受け取ることができる\n報酬があるようです\n確認してみてください", 0.0, -416.5, 1, "2026/04/10 12:00:00", 63, 190801, 2.801, 2, 2, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 4, 2000004, "報酬がもらえますよ！\nチェックしてみてください", 0.0, -416.5, 2, "2026/04/10 12:00:00", 63, 190801, 0.0, 2, 2, "カリン");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 5, 2000005, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 0.0, -363.0, 2, "2026/04/10 12:00:00", 64, 190801, 2.12, 1, 2, "カリン");
